import React, { useState } from 'react';
import { getDigitalAdvice } from '../services/geminiService';

const AIAdvisor: React.FC = () => {
  const [query, setQuery] = useState('');
  const [response, setResponse] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setIsLoading(true);
    setResponse(null);
    try {
      const advice = await getDigitalAdvice(query);
      setResponse(advice);
    } catch (err) {
      setResponse("Une erreur est survenue lors de la consultation.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section className="py-16 bg-gradient-to-br from-slate-900 to-slate-800 text-white relative overflow-hidden">
      <div className="absolute top-0 right-0 p-8 opacity-10">
        <svg className="w-32 h-32" fill="currentColor" viewBox="0 0 24 24">
          <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z" />
        </svg>
      </div>

      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        <div className="text-center mb-10">
          <h2 className="text-3xl font-bold mb-4">Posez-moi une question technique</h2>
          <p className="text-slate-400">
            Obtenez un premier avis sur votre projet digital directement via mon assistant IA entraîné sur mon expertise locale.
          </p>
        </div>

        <div className="bg-white/5 border border-white/10 rounded-2xl p-6 backdrop-blur-sm">
          <form onSubmit={handleSubmit} className="mb-6">
            <div className="flex flex-col sm:flex-row gap-4">
              <input
                type="text"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="Ex: Comment sécuriser mon réseau boutique avec un petit budget ?"
                className="flex-grow bg-slate-800/50 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-orange-500 placeholder-slate-500"
              />
              <button
                type="submit"
                disabled={isLoading || !query.trim()}
                className="bg-orange-500 hover:bg-orange-600 disabled:opacity-50 text-slate-900 font-bold px-6 py-3 rounded-lg transition-all flex items-center justify-center min-w-[120px]"
              >
                {isLoading ? (
                  <svg className="animate-spin h-5 w-5 text-slate-900" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                ) : "Conseiller"}
              </button>
            </div>
          </form>

          {response && (
            <div className="bg-white/10 rounded-xl p-5 border-l-4 border-orange-500 animate-in fade-in slide-in-from-top-4 duration-500">
              <div className="flex items-center mb-3">
                <div className="w-8 h-8 rounded-full bg-orange-500 flex items-center justify-center text-slate-900 mr-3 text-xs font-bold">
                  AM
                </div>
                <span className="text-sm font-semibold text-orange-400 italic">Réponse d'Alexis (AI Advisor)</span>
              </div>
              <p className="text-slate-200 text-sm leading-relaxed whitespace-pre-wrap">
                {response}
              </p>
            </div>
          )}
        </div>
      </div>
    </section>
  );
};

