interface NavbarProps {
  currentPage: Page;
  onNavigate: (page: Page) => void;
}

const Navbar: React.FC<NavbarProps> = ({ currentPage, onNavigate }) => {
  const [isOpen, setIsOpen] = useState(false);

  const links: { name: string; id: Page }[] = [
    { name: 'Accueil', id: 'home' },
    { name: 'Services', id: 'services' },
    { name: 'Compétences', id: 'solutions' },
    { name: 'Tarifs', id: 'pricing' },
    { name: 'Contact', id: 'contact' },
  ];

  const handleNav = (id: Page) => {
    onNavigate(id);
    setIsOpen(false);
  };

  return (
    <nav className="bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-20 items-center">
          <div 
            className="flex-shrink-0 flex items-center cursor-pointer group"
            onClick={() => handleNav('home')}
          >
            <div className="w-10 h-10 bg-orange-600 rounded-lg flex items-center justify-center text-white font-bold text-xl mr-3 group-hover:rotate-6 transition-transform">
              A
            </div>
            <div className="flex flex-col">
              <span className="text-lg font-bold text-slate-900 leading-tight">Alexis Mupole</span>
              <span className="text-[10px] uppercase tracking-widest text-orange-600 font-semibold">Étudiant Développeur</span>
            </div>
          </div>

          <div className="hidden md:flex items-center space-x-1">
            {links.map((link) => (
              <button
                key={link.id}
                onClick={() => handleNav(link.id)}
                className={`px-4 py-2 rounded-full text-sm font-medium transition-all ${
                  currentPage === link.id 
                    ? 'text-orange-600 bg-orange-50' 
                    : 'text-slate-600 hover:text-orange-600 hover:bg-slate-50'
                }`}
              >
                {link.name}
              </button>
            ))}
          </div>

          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="text-slate-600 hover:text-slate-900 focus:outline-none p-2"
            >
              <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                {isOpen ? (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                ) : (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                )}
              </svg>
            </button>
          </div>
        </div>
      </div>

      {isOpen && (
        <div className="md:hidden bg-white border-t border-slate-100 py-4 px-4 space-y-2 shadow-xl">
          {links.map((link) => (
            <button
              key={link.id}
              onClick={() => handleNav(link.id)}
              className={`block w-full text-left px-4 py-3 rounded-xl text-base font-medium transition-colors ${
                currentPage === link.id 
                  ? 'text-orange-600 bg-orange-50' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              {link.name}
            </button>
          ))}
        </div>
      )}
    </nav>
  );
};

export default Navbar;

