              <span className="text-lg font-black text-slate-900 leading-tight tracking-tight">ALEXIS MUPOLE</span>
              <span className="text-[10px] uppercase tracking-[0.2em] text-blue-600 font-bold">Digital Engineering</span>
            </div>
          </div>

          <div className="hidden md:flex items-center space-x-2">
            {links.map((link) => (
              <button
                key={link.id}
                onClick={() => handleNav(link.id)}
                className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all duration-300 ${
                  currentPage === link.id 
                    ? 'text-white bg-slate-950 shadow-lg shadow-blue-500/10' 
                    : 'text-slate-600 hover:text-blue-600 hover:bg-blue-50'
